import json

import yaml

from prompty.model import TokenEventPayload


def test_load_json_tokeneventpayload():
    json_data = r"""
    {
      "token": "Hello"
    }
    """
    data = json.loads(json_data, strict=False)
    instance = TokenEventPayload.load(data)
    assert instance is not None
    assert instance.token == "Hello"


def test_load_yaml_tokeneventpayload():
    yaml_data = r"""
    token: Hello

    """
    data = yaml.load(yaml_data, Loader=yaml.FullLoader)
    instance = TokenEventPayload.load(data)
    assert instance is not None
    assert instance.token == "Hello"


def test_roundtrip_json_tokeneventpayload():
    """Test that load -> save -> load produces equivalent data."""
    json_data = r"""
    {
      "token": "Hello"
    }
    """
    original_data = json.loads(json_data, strict=False)
    instance = TokenEventPayload.load(original_data)
    saved_data = instance.save()
    reloaded = TokenEventPayload.load(saved_data)
    assert reloaded is not None
    assert reloaded.token == "Hello"


def test_to_json_tokeneventpayload():
    """Test that to_json produces valid JSON."""
    json_data = r"""
    {
      "token": "Hello"
    }
    """
    data = json.loads(json_data, strict=False)
    instance = TokenEventPayload.load(data)
    json_output = instance.to_json()
    assert json_output is not None
    parsed = json.loads(json_output)
    assert isinstance(parsed, dict)


